// RocketMQ OAuth Bootstrap Bridge
// This file bridges the ESM-based OIDC modules with the global window scope
// expected by the RabbitMQ management UI's index.html inline module script.
//
// In the official RabbitMQ server, this file is dynamically generated by the
// Erlang backend. Since our Rust broker serves static files, we provide a
// static bridge that exposes the necessary functions.

import { oauth_initialize_if_required, set_oauth_settings } from './helper.js';

// Expose to global scope so the inline <script type="module"> in index.html
// can call oauth_initialize_if_required() and set window.oauth
window.oauth_initialize_if_required = oauth_initialize_if_required;
window.set_oauth_settings = set_oauth_settings;

// Also make check_version available in module scope (it's defined in main.js
// as a regular script, so it's already on window — this is just a safety net)
if (typeof window.check_version === 'undefined') {
    window.check_version = function() {
        // no-op fallback; the real implementation in main.js will override this
    };
}
